 function rankStatusContexts(
   items: Array<{ context: string; state: 'pending' | 'success' | 'failure' | 'error' }>,
   state: 'pending' | 'failure' | 'error',
   limit: number
 ): string[] {
   return items
     .filter((item) => item.state === state)
     .map((item) => item.context)
     .sort((a, b) => a.localeCompare(b))
     .slice(0, limit);
 }

